    fn test_layout_metadata_new() {
        let metadata = LayoutMetadata::new("Test Layout").unwrap();
        assert_eq!(metadata.name, "Test Layout");
        assert!(metadata.description.is_empty());
        assert!(metadata.author.is_empty());
